import{_ as s,C as n,o as t,c as i,a2 as o,b as d,w as a,a as l,E as g,a3 as u}from"./chunks/framework.DXCpk3D_.js";const w=JSON.parse('{"title":"Why Open Agent Orchestra?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/why-oao.md","filePath":"guide/why-oao.md"}'),c={name:"guide/why-oao.md"};function p(h,e,A,m,I,C){const r=n("Mermaid");return t(),i("div",null,[e[1]||(e[1]=o('<h1 id="why-open-agent-orchestra" tabindex="-1">Why Open Agent Orchestra? <a class="header-anchor" href="#why-open-agent-orchestra" aria-label="Permalink to &quot;Why Open Agent Orchestra?&quot;">​</a></h1><p>AI is transforming software development, customer support, DevOps, and knowledge work. But most organizations hitting &quot;AI adoption&quot; face the same question:</p><blockquote><p><strong>How do we move from one-off AI chat sessions to production-grade, autonomous workflows that integrate with the systems we already use?</strong></p></blockquote><h2 id="the-gap-between-ai-demos-and-production" tabindex="-1">The Gap Between AI Demos and Production <a class="header-anchor" href="#the-gap-between-ai-demos-and-production" aria-label="Permalink to &quot;The Gap Between AI Demos and Production&quot;">​</a></h2><p>Most AI tools today work well in isolation — a developer asks a question, an LLM answers. But enterprises need much more:</p><table tabindex="0"><thead><tr><th>What teams need</th><th>What most tools offer</th></tr></thead><tbody><tr><td>AI agents embedded in existing workflows (Jira, GitHub, Slack, Trello)</td><td>Standalone chatbots</td></tr><tr><td>Multi-step pipelines that run autonomously on a schedule or webhook</td><td>One-shot prompt/response</td></tr><tr><td>Secure credential management across teams</td><td>Environment variables or plain text</td></tr><tr><td>Role-based access and audit trails for compliance</td><td>No governance</td></tr><tr><td>Cost controls and per-user/per-team quotas</td><td>Unlimited spend</td></tr><tr><td>Human-in-the-loop hybrid flows with approval gates</td><td>Fully autonomous or fully manual</td></tr></tbody></table><p>This is the <strong>&quot;last mile&quot; problem</strong> of enterprise AI adoption: bridging the gap between an impressive demo and a system your operations team can rely on.</p><h2 id="what-oao-solves" tabindex="-1">What OAO Solves <a class="header-anchor" href="#what-oao-solves" aria-label="Permalink to &quot;What OAO Solves&quot;">​</a></h2><p>Open Agent Orchestra is a <strong>workflow orchestration platform</strong> purpose-built for AI agents. It provides the missing infrastructure between your AI models and your business processes.</p>',9)),(t(),d(u,null,{default:a(()=>[g(r,{id:"mermaid-88",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20External%5B%22External%20Systems%22%5D%0A%20%20%20%20%20%20%20%20JIRA%5B%22Jira%20%2F%20Trello%22%5D%0A%20%20%20%20%20%20%20%20GH%5B%22GitHub%22%5D%0A%20%20%20%20%20%20%20%20SLACK%5B%22Slack%20%2F%20Email%22%5D%0A%20%20%20%20%20%20%20%20API%5B%22Any%20REST%20API%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20OAO%5B%22Open%20Agent%20Orchestra%22%5D%0A%20%20%20%20%20%20%20%20TRIGGER%5B%22Triggers%22%5D%0A%20%20%20%20%20%20%20%20ENGINE%5B%22Workflow%20Engine%22%5D%0A%20%20%20%20%20%20%20%20AGENTS%5B%22AI%20Agents%22%5D%0A%20%20%20%20%20%20%20%20CREDS%5B%22Credential%20Vault%22%5D%0A%20%20%20%20%20%20%20%20AUDIT%5B%22Audit%20%26%20Events%22%5D%0A%20%20%20%20%20%20%20%20QUOTA%5B%22Quotas%20%26%20RBAC%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20AI%5B%22AI%20Backbone%22%5D%0A%20%20%20%20%20%20%20%20COPILOT%5B%22GitHub%20Copilot%20SDK%22%5D%0A%20%20%20%20%20%20%20%20MCP%5B%22MCP%20Servers%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20JIRA%20--%20webhook%20--%3E%20TRIGGER%0A%20%20%20%20GH%20--%20webhook%20--%3E%20TRIGGER%0A%20%20%20%20TRIGGER%20--%3E%20ENGINE%0A%20%20%20%20ENGINE%20--%3E%20AGENTS%0A%20%20%20%20AGENTS%20--%3E%20COPILOT%0A%20%20%20%20AGENTS%20--%3E%20MCP%0A%20%20%20%20MCP%20--%3E%20API%0A%20%20%20%20MCP%20--%3E%20SLACK%0A%20%20%20%20CREDS%20-.-%3E%20AGENTS%0A%20%20%20%20QUOTA%20-.-%3E%20AGENTS%0A%20%20%20%20ENGINE%20--%3E%20AUDIT%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<div class="mermaid-source" data-mermaid-source=""></div><h3 id="key-capabilities" tabindex="-1">Key Capabilities <a class="header-anchor" href="#key-capabilities" aria-label="Permalink to &quot;Key Capabilities&quot;">​</a></h3><p><strong>1. Workflow Orchestration</strong></p><p>Define multi-step AI workflows where each step can use a different agent, model, or reasoning level. Steps execute in sequence with the output of one step feeding into the next via Jinja2 template variables. Workflows support cron schedules, one-time triggers, webhooks, and event-based triggers.</p><p><strong>2. Agent Segregation of Duties</strong></p><p>Each workflow step can use a different agent with different instructions, skills, and tool access. A &quot;Read-Only Analyst&quot; agent can gather data, while a &quot;Writer&quot; agent with different credentials creates the report. This mirrors enterprise security patterns: least-privilege access, separation of concerns.</p><p><strong>3. Secure Credential Management</strong></p><p>All secrets are encrypted at rest with AES-256-GCM. Variables follow a 3-tier scoping model (Agent → User → Workspace) so credentials can be shared across a team without exposing raw values. MCP server environment mappings inject credentials at runtime without ever writing them to disk in plaintext.</p><p><strong>4. Webhook Integration</strong></p><p>OAO accepts incoming webhooks from any system — Jira, GitHub, Trello, PagerDuty, custom apps — with HMAC-SHA256 signature verification, replay protection, and event deduplication. When a webhook fires, OAO injects the payload data into the workflow prompt template automatically.</p><p><strong>5. Cost Controls and Quotas</strong></p><p>Set daily, weekly, and monthly credit limits at the workspace and user level. Track usage by model, by agent, by day. Prevent runaway costs before they happen — not after the bill arrives.</p><p><strong>6. Role-Based Access Control</strong></p><p>Four roles (<code>super_admin</code>, <code>workspace_admin</code>, <code>creator_user</code>, <code>view_user</code>) control who can create agents, run workflows, manage credentials, or administer the platform. Supports database and LDAP authentication providers.</p><p><strong>7. Observability and Audit</strong></p><p>Every workflow execution records step-by-step output, reasoning traces (tool calls, intermediate results), live streaming via SSE, and system events. The event bus provides a full audit trail for compliance — who ran what, when, with which inputs, and what the AI decided.</p><h2 id="who-is-this-for" tabindex="-1">Who Is This For? <a class="header-anchor" href="#who-is-this-for" aria-label="Permalink to &quot;Who Is This For?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>How OAO Helps</th></tr></thead><tbody><tr><td><strong>Platform Engineers</strong></td><td>Deploy a self-hosted AI workflow engine with Helm on Kubernetes. No vendor lock-in, full control.</td></tr><tr><td><strong>DevOps / SRE Teams</strong></td><td>Automate incident triage, runbook execution, and reporting with scheduled + event-driven workflows.</td></tr><tr><td><strong>Engineering Managers</strong></td><td>Give developers AI agent access with guardrails — cost limits, audit trails, role-based permissions.</td></tr><tr><td><strong>Security &amp; Compliance</strong></td><td>AES-256-GCM credential encryption, HMAC webhook auth, LDAP integration, full event audit trail.</td></tr><tr><td><strong>Product Teams</strong></td><td>Build AI-powered workflows that connect to Jira, GitHub, Slack — no custom infrastructure needed.</td></tr><tr><td><strong>AI/ML Engineers</strong></td><td>Configure agents with MCP servers, custom tools, and per-step model/reasoning selection.</td></tr></tbody></table><h2 id="the-copilot-sdk-advantage" tabindex="-1">The Copilot SDK Advantage <a class="header-anchor" href="#the-copilot-sdk-advantage" aria-label="Permalink to &quot;The Copilot SDK Advantage&quot;">​</a></h2><p>OAO is built on the <strong>GitHub Copilot SDK</strong> — the same infrastructure powering GitHub Copilot. This means:</p><ul><li><strong>Model-agnostic</strong>: Use any model available through the Copilot model catalog (GPT-4o, Claude, etc.)</li><li><strong>Tool ecosystem</strong>: Native MCP (Model Context Protocol) support for connecting to thousands of existing tools</li><li><strong>Enterprise-ready auth</strong>: GitHub-based authentication with token management</li><li><strong>Active development</strong>: Backed by GitHub&#39;s investment in AI developer tools</li></ul><h2 id="open-source-self-hosted" tabindex="-1">Open Source, Self-Hosted <a class="header-anchor" href="#open-source-self-hosted" aria-label="Permalink to &quot;Open Source, Self-Hosted&quot;">​</a></h2><p>OAO is MIT-licensed and designed for self-hosting. Your data stays on your infrastructure. Your credentials never leave your cluster. Your AI workflows run on your terms.</p><ul><li><strong>Docker Compose</strong> for quick local development</li><li><strong>Helm Charts</strong> for production Kubernetes deployments</li><li><strong>No cloud dependencies</strong> — runs on Docker Desktop, Minikube, or any Kubernetes cluster</li></ul><div class="info custom-block"><p class="custom-block-title">Ready to get started?</p><p>Head to the <a href="/open-agent-orchestra/1.30.11/guide/docker.html">Docker setup guide</a> or the <a href="/open-agent-orchestra/1.30.11/guide/kubernetes.html">Kubernetes deployment guide</a> to run OAO in minutes.</p></div>',25))])}const f=s(c,[["render",p]]);export{w as __pageData,f as default};
